{quote}{ "aggregate" : "students", "pipeline" : [{ "$project" : { "Id" : "$_id", "Scores" : { "$filter" : { "input" : "$scores", "as" : "sc1", "cond" : {{color:#d04437} "$gt" : ["$$sc1.score", \{ "$min" : "$$sc1.scores.score" }]{color} } } }, "_id" : 0 } }], "cursor" : \{ }, "lsid" : \{ "id" : CSUUID("8cea95ec-7e89-4752-a3d4-9d7ea628cef9") } }
